INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 10, "シズルさまにエリコさま、\nどうかされたのですか？", 1, 0, 0, 11, 107611, 0.5, 19050041, 905);
