INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 10, "なんですか、その気持ちの悪い根拠は。\nそれよりも、あの方はどこにおられるのか\n知っているのでしょう？\n隠し立ては許しませんよ。", 1, 0, 0, 11, 117011, 0.5, 19050051, 905);
