INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (1, 0, "45_yui_shy_in", "45_yui_shy_loop", 0.1, 0.1, 3, 1, "", 19450031, 945);
